export const code = async (inputs) => {
  const pv = inputs.patient || {};
  const patientRow = inputs.patientRow || '';
  const clinics = Array.isArray(inputs.clinics) ? inputs.clinics : [];

  const clinicId  = pv['C'] || '';
  const phone     = pv['F'] || '';
  const name      = pv['D'] || 'Patient';
  const corrId    = pv['B'] || '';
  const alertSent = (pv['Q'] || '').toString().toUpperCase();
  const followupDate = pv['G'] || '';

  // IDEMPOTENCY: skip if alert already sent
  if (alertSent === 'TRUE') {
    return { skip: true, reason: 'alert_already_sent' };
  }

  const clinic = clinics.find(c => {
    const cv = c['values'] || c;
    return (cv['A'] || '').toString().trim() === clinicId.trim();
  });

  if (!clinic) {
    return { skip: true, reason: 'clinic_not_found', clinicId };
  }

  const cv = clinic['values'] || clinic;
  const waToken       = cv['C'] || '';
  const phoneNumberId = cv['D'] || '';
  const ownerPhone    = cv['F'] || '';
  const clinicName    = cv['B'] || 'Clinic';

  return {
    skip: false,
    phone,
    name,
    corrId,
    clinicId,
    clinicName,
    waToken,
    phoneNumberId,
    ownerPhone,
    followupDate,
    patientRow
  };
};

