export const code = async (inputs) => {
  // patients columns:
  // A=patient_id B=corr_id C=clinic_id D=patient_name E=phone_raw F=phone_cleaned
  // G=followup_date H=status I=processing_lock J=sentiment K=delivery_status
  // L=delivered_at M=read_at N=replied_at O=review_requested P=review_sent_at
  // Q=alert_sent R=alert_sent_at S=opted_out T=registered_at U=wf_version
  const pv = inputs.patient || {};
  const patientRow = inputs.patientRow || '';
  const clinics = Array.isArray(inputs.clinics) ? inputs.clinics : [];

  const clinicId    = pv['C'] || '';
  const phone       = pv['F'] || '';
  const name        = pv['D'] || 'Patient';
  const corrId      = pv['B'] || '';
  const reviewRequested = (pv['O'] || '').toString().toUpperCase();
  const repliedAt   = pv['N'] || '';

  // IDEMPOTENCY: skip if review already requested
  if (reviewRequested === 'TRUE') {
    return { skip: true, reason: 'review_already_requested' };
  }

  // Find clinic credentials
  // clinics columns: A=clinic_id B=clinic_name C=wa_token D=phone_number_id
  // E=google_review_link F=owner_phone G=owner_email H=review_delay_m I=is_active J=created_at
  const clinic = clinics.find(c => {
    const cv = c['values'] || c;
    return (cv['A'] || '').toString().trim() === clinicId.trim();
  });

  if (!clinic) {
    return { skip: true, reason: 'clinic_not_found', clinicId };
  }

  const cv = clinic['values'] || clinic;
  const waToken       = cv['C'] || '';
  const phoneNumberId = cv['D'] || '';
  const reviewLink    = cv['E'] || '';
  const delayMinutes  = parseInt(cv['H'] || '30', 10);

  // Check if enough time has passed since patient replied
  // Architecture says 30 min delay before review request
  if (repliedAt) {
    const repliedMs = new Date(repliedAt).getTime();
    const nowMs = Date.now();
    const minutesPassed = (nowMs - repliedMs) / (1000 * 60);
    if (minutesPassed < delayMinutes) {
      return { skip: true, reason: 'too_soon', minutesPassed: Math.floor(minutesPassed), delayMinutes };
    }
  }

  return {
    skip: false,
    phone,
    name,
    corrId,
    clinicId,
    waToken,
    phoneNumberId,
    reviewLink,
    patientRow
  };
};
